import { useEffect, useMemo, useRef, useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { toast } from 'sonner';
import { StepperDialog, type StepperDialogStep } from '@/components/ui/StepperDialog';
import { ApiError } from '@/lib/api';
import { Icon } from '@/components/Icon';
import { useRecipientsQuery, NOTIFICATION_TYPE_LABEL } from '@/routes/recipients/queries';
import { useQueriesListQuery, useQueryDetailQuery } from '@/routes/queries/queries';
import { useCreateSubscription } from './queries';

const SCHEMA = z.object({
  queryId: z.number({ message: 'Query id is required' }).int().min(1, 'Query id is required'),
  cronExpression: z.string().trim().min(1, 'Cron expression is required').max(200),
  recipientIds: z.array(z.number().int()).min(1, 'Pick at least one recipient'),
  maxRows: z.number().int().min(0).nullable().optional(),
  timeoutSeconds: z.number().int().min(0).nullable().optional(),
  includeAttachment: z.boolean(),
  showQuery: z.boolean(),
  storeResults: z.boolean(),
  createTasks: z.boolean(),
});

type FormValues = z.infer<typeof SCHEMA>;

const DEFAULTS: FormValues = {
  queryId: 0,
  cronExpression: '0 9 * * *',
  recipientIds: [],
  maxRows: null,
  timeoutSeconds: null,
  includeAttachment: false,
  showQuery: false,
  storeResults: false,
  createTasks: false,
};

interface AddSubscriptionDialogProps {
  open: boolean;
  onClose: () => void;
  initialQueryId?: number;
}

export function AddSubscriptionDialog({ open, onClose, initialQueryId }: AddSubscriptionDialogProps) {
  const { data: recipientsData, isLoading: recipientsLoading } = useRecipientsQuery();
  const createMutation = useCreateSubscription();

  const form = useForm<FormValues>({
    resolver: zodResolver(SCHEMA),
    defaultValues: DEFAULTS,
    mode: 'onTouched',
  });
  const { register, watch, setValue, reset, formState: { errors } } = form;

  useEffect(() => {
    if (!open) return;
    reset({ ...DEFAULTS, queryId: initialQueryId ?? 0 });
  }, [open, reset, initialQueryId]);

  const recipients = recipientsData?.entries ?? [];
  const recipientIds = watch('recipientIds');
  const queryId = watch('queryId');
  const cronExpression = watch('cronExpression');

  const selectedRecipients = useMemo(
    () => recipients.filter(r => recipientIds.includes(r.id)),
    [recipients, recipientIds],
  );

  const toggleRecipient = (id: number) => {
    const current = new Set(recipientIds);
    if (current.has(id)) {
      current.delete(id);
    } else {
      current.add(id);
    }
    setValue('recipientIds', Array.from(current), { shouldValidate: true });
  };

  const onFinish = async () => {
    const values = form.getValues();
    try {
      await createMutation.mutateAsync({
        queryId: values.queryId,
        cronExpression: values.cronExpression,
        recipientIds: values.recipientIds,
        maxRows: values.maxRows ?? null,
        timeoutSeconds: values.timeoutSeconds ?? null,
        includeAttachment: values.includeAttachment,
        showQuery: values.showQuery,
        storeResults: values.storeResults,
        createTasks: values.createTasks,
      });
      toast.success('Subscription created');
      onClose();
    } catch (err) {
      const message = err instanceof ApiError
        ? err.body || `Request failed (${err.status})`
        : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  };

  const steps: StepperDialogStep<FormValues>[] = [
    {
      id: 'query',
      title: 'Query',
      description: 'Pick a query and schedule.',
      fields: ['queryId', 'cronExpression'],
      render: () => (
        <>
          <div className="q-field">
            <label className="q-label">
              Query<span className="q-label__req">*</span>
            </label>
            <QueryPicker
              value={queryId || null}
              onChange={id => setValue('queryId', id ?? 0, { shouldValidate: true })}
              hasError={!!errors.queryId}
            />
            {errors.queryId && <div className="q-error">{errors.queryId.message}</div>}
          </div>

          <div className="q-field" style={{ marginTop: 14 }}>
            <label className="q-label" htmlFor="sub-cron">
              Cron expression<span className="q-label__req">*</span>
            </label>
            <input
              id="sub-cron"
              type="text"
              className={`q-input mono${errors.cronExpression ? ' q-input--error' : ''}`}
              placeholder="0 9 * * *"
              {...register('cronExpression')}
            />
            <div className="q-help">
              Standard 5-field cron. Example: <span className="mono">0 9 * * *</span> runs daily at 09:00.
            </div>
            {errors.cronExpression && <div className="q-error">{errors.cronExpression.message}</div>}
          </div>
        </>
      ),
    },
    {
      id: 'recipients',
      title: 'Recipients',
      description: 'Where alerts are delivered.',
      fields: ['recipientIds'],
      render: () => (
        <>
          <div className="q-field">
            <label className="q-label">
              Recipients<span className="q-label__req">*</span>
            </label>
            {recipientsLoading && <div className="muted">Loading recipients…</div>}
            {!recipientsLoading && recipients.length === 0 && (
              <div className="muted">
                No recipients yet. Add one from the Recipients page first.
              </div>
            )}
            {!recipientsLoading && recipients.length > 0 && (
              <div
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 6,
                  maxHeight: 220,
                  overflow: 'auto',
                }}
              >
                {recipients.map(r => {
                  const checked = recipientIds.includes(r.id);
                  return (
                    <label
                      key={r.id}
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 8,
                        padding: '6px 8px',
                        border: '1px solid var(--border)',
                        borderRadius: 8,
                        cursor: 'pointer',
                      }}
                    >
                      <input
                        type="checkbox"
                        checked={checked}
                        onChange={() => toggleRecipient(r.id)}
                      />
                      <span style={{ fontWeight: 500 }}>{r.name}</span>
                      <span className="muted mono" style={{ fontSize: 12 }}>
                        {r.destination}
                      </span>
                      <span
                        className="pill pill--neutral mono"
                        style={{ fontSize: 10, marginLeft: 'auto' }}
                      >
                        {NOTIFICATION_TYPE_LABEL[r.notificationType] ?? r.notificationType}
                      </span>
                    </label>
                  );
                })}
              </div>
            )}
            {errors.recipientIds && (
              <div className="q-error">{errors.recipientIds.message as string}</div>
            )}
          </div>

          <div className="q-field" style={{ marginTop: 14 }}>
            <label className="q-label" htmlFor="sub-max-rows">Max rows</label>
            <input
              id="sub-max-rows"
              type="number"
              className="q-input"
              placeholder="No limit"
              {...register('maxRows', {
                setValueAs: v => (v === '' || v == null ? null : Number(v)),
              })}
            />
          </div>

          <div className="q-field" style={{ marginTop: 14 }}>
            <label className="q-label" htmlFor="sub-timeout">Timeout (seconds)</label>
            <input
              id="sub-timeout"
              type="number"
              className="q-input"
              placeholder="Default"
              {...register('timeoutSeconds', {
                setValueAs: v => (v === '' || v == null ? null : Number(v)),
              })}
            />
          </div>

          <div className="q-field" style={{ marginTop: 14, display: 'grid', gap: 6 }}>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="checkbox" {...register('includeAttachment')} />
              <span>Include results as attachment</span>
            </label>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="checkbox" {...register('showQuery')} />
              <span>Show query text in notification</span>
            </label>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="checkbox" {...register('storeResults')} />
              <span>Store result rows for later viewing</span>
            </label>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="checkbox" {...register('createTasks')} />
              <span>Create tasks for each result row</span>
            </label>
          </div>
        </>
      ),
    },
    {
      id: 'review',
      title: 'Review',
      description: 'Confirm and create.',
      render: () => {
        const values = form.getValues();
        return (
          <dl className="stepper__review">
            <dt>Query</dt>
            <dd>
              <SelectedQueryLabel id={queryId} />
            </dd>
            <dt>Schedule</dt>
            <dd className="mono">{cronExpression}</dd>
            <dt>Recipients</dt>
            <dd>
              {selectedRecipients.length === 0
                ? <span className="muted">None selected</span>
                : (
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                    {selectedRecipients.map(r => (
                      <span key={r.id}>
                        {r.name}{' '}
                        <span className="muted mono" style={{ fontSize: 12 }}>
                          {r.destination}
                        </span>
                      </span>
                    ))}
                  </div>
                )}
            </dd>
            <dt>Max rows</dt>
            <dd>{values.maxRows ?? <span className="muted">No limit</span>}</dd>
            <dt>Timeout</dt>
            <dd>
              {values.timeoutSeconds == null
                ? <span className="muted">Default</span>
                : <span className="mono">{values.timeoutSeconds}s</span>}
            </dd>
            <dt>Options</dt>
            <dd>
              {[
                values.includeAttachment && 'Attachment',
                values.showQuery && 'Show query',
                values.storeResults && 'Store results',
                values.createTasks && 'Create tasks',
              ].filter(Boolean).join(', ') || <span className="muted">None</span>}
            </dd>
          </dl>
        );
      },
    },
  ];

  return (
    <StepperDialog<FormValues>
      open={open}
      onClose={onClose}
      title="New subscription"
      sub="Schedule a query and route its results to recipients."
      steps={steps}
      form={form}
      onFinish={onFinish}
      busy={createMutation.isPending}
      finishLabel="Create subscription"
    />
  );
}

// ---------------------------------------------------------------------------
// Searchable query picker — server-side search via /beacon/api/queries/.
// ---------------------------------------------------------------------------

interface QueryPickerProps {
  value: number | null;
  onChange: (id: number | null) => void;
  hasError?: boolean;
}

function QueryPicker({ value, onChange, hasError }: QueryPickerProps) {
  const [open, setOpen] = useState(false);
  const [term, setTerm] = useState('');
  const [debounced, setDebounced] = useState('');
  const [highlight, setHighlight] = useState(0);
  const containerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const t = window.setTimeout(() => setDebounced(term.trim()), 200);
    return () => window.clearTimeout(t);
  }, [term]);

  const list = useQueriesListQuery({ searchTerm: debounced || undefined, pageSize: 20 });
  const selected = useQueryDetailQuery(value ?? undefined);

  useEffect(() => {
    if (!open) return;
    const onDocClick = (e: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', onDocClick);
    return () => document.removeEventListener('mousedown', onDocClick);
  }, [open]);

  useEffect(() => {
    if (open) requestAnimationFrame(() => inputRef.current?.focus());
  }, [open]);

  const items = list.data?.items ?? [];
  const totalCount = list.data?.totalCount ?? 0;

  const selectedName = value != null && value > 0
    ? selected.data?.name ?? `#${value}`
    : null;

  const pick = (id: number) => {
    onChange(id);
    setOpen(false);
    setTerm('');
  };

  const onKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setHighlight(h => Math.min(h + 1, items.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setHighlight(h => Math.max(h - 1, 0));
    } else if (e.key === 'Enter') {
      e.preventDefault();
      const item = items[highlight];
      if (item) pick(item.queryId);
    } else if (e.key === 'Escape') {
      e.preventDefault();
      setOpen(false);
    }
  };

  return (
    <div ref={containerRef} style={{ position: 'relative' }}>
      {!open && (
        <button
          type="button"
          className={`q-input${hasError ? ' q-input--error' : ''}`}
          onClick={() => setOpen(true)}
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 8,
            width: '100%',
            cursor: 'pointer',
            textAlign: 'left',
            justifyContent: 'space-between',
          }}
        >
          {selectedName
            ? (
              <span style={{ display: 'flex', alignItems: 'center', gap: 8, minWidth: 0 }}>
                <span style={{ fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {selectedName}
                </span>
                <span className="muted mono" style={{ fontSize: 12 }}>#{value}</span>
              </span>
            )
            : <span className="muted">Search queries by name…</span>}
          <Icon.Chevron size={14} className="muted" />
        </button>
      )}

      {open && (
        <>
          <input
            ref={inputRef}
            type="text"
            className={`q-input${hasError ? ' q-input--error' : ''}`}
            value={term}
            placeholder="Type to search queries…"
            onChange={e => { setTerm(e.target.value); setHighlight(0); }}
            onKeyDown={onKeyDown}
            autoComplete="off"
          />
          <div
            style={{
              position: 'absolute',
              top: 'calc(100% + 4px)',
              left: 0,
              right: 0,
              zIndex: 10,
              background: 'var(--surface)',
              border: '1px solid var(--border)',
              borderRadius: 'var(--r-sm)',
              boxShadow: 'var(--shadow-pop)',
              maxHeight: 280,
              overflow: 'auto',
            }}
          >
            {list.isLoading && (
              <div className="muted" style={{ padding: 12, fontSize: 13 }}>Searching…</div>
            )}
            {!list.isLoading && items.length === 0 && (
              <div className="muted" style={{ padding: 12, fontSize: 13 }}>
                {debounced ? `No queries match "${debounced}".` : 'No queries yet.'}
              </div>
            )}
            {!list.isLoading && items.map((q, i) => (
              <button
                type="button"
                key={q.queryId}
                onClick={() => pick(q.queryId)}
                onMouseEnter={() => setHighlight(i)}
                style={{
                  display: 'flex',
                  width: '100%',
                  alignItems: 'center',
                  gap: 8,
                  padding: '8px 12px',
                  border: 'none',
                  background: i === highlight ? 'var(--surface-2)' : 'transparent',
                  cursor: 'pointer',
                  textAlign: 'left',
                  font: 'inherit',
                  color: 'inherit',
                }}
              >
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {q.name}
                  </div>
                  {q.description && (
                    <div className="muted" style={{ fontSize: 11.5, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {q.description}
                    </div>
                  )}
                </div>
                <span className="muted mono" style={{ fontSize: 11 }}>#{q.queryId}</span>
                {q.subscriptionsCount > 0 && (
                  <span className="pill" style={{ fontSize: 10 }}>{q.subscriptionsCount} sub{q.subscriptionsCount === 1 ? '' : 's'}</span>
                )}
              </button>
            ))}
            {!list.isLoading && totalCount > items.length && (
              <div className="muted" style={{ padding: '6px 12px', fontSize: 11, borderTop: '1px solid var(--border)' }}>
                Showing {items.length} of {totalCount}. Refine your search to narrow.
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
}

function SelectedQueryLabel({ id }: { id: number }) {
  const detail = useQueryDetailQuery(id > 0 ? id : undefined);
  if (id <= 0) return <span className="muted">None selected</span>;
  return (
    <>
      <span style={{ fontWeight: 600 }}>{detail.data?.name ?? `#${id}`}</span>
      <span className="muted mono" style={{ marginLeft: 6, fontSize: 12 }}>#{id}</span>
    </>
  );
}
